/**
 * Milestone-1 ceiling benchmark for the Janino codegen plan
 * (plans/lmdb-native-engine/17-janino-whole-stage-codegen.md): measures the native engine against the hand-written
 * ideal fused kernels ({@link JaninoCeilingKernels}) on the full-size FOAF-clique dataset (identical parameters to
 * {@link FoafCliqueQueryBenchmark}). The fused numbers are the physical upper bound for M3+ generated code of the same
 * design; correctness of the kernels is pinned by {@link JaninoCeilingParityTest}.
 */
@State(Scope.Benchmark)
@org.openjdk.jmh.annotations.Warmup(iterations = 5, time = 1, timeUnit = TimeUnit.SECONDS)
@BenchmarkMode({ Mode.AverageTime })
@Fork(value = 1, jvmArgs = { "-Xms2G", "-Xmx2G", "-XX:+UseG1GC" })
@Measurement(iterations = 5, time = 1, timeUnit = TimeUnit.SECONDS)
@OutputTimeUnit(TimeUnit.MILLISECONDS)
public class JaninoCeilingBenchmark {

	@Param({ "native" })
	public String engineMode;

	private final ValueFactory vf = SimpleValueFactory.getInstance();
	private File dataDir;
	private SailRepository repository;
	private SailDataset dataset;
	private NativeLmdbQuerySource source;
	private NativeLmdbQuerySource.NativeProbe probe;
	private NativeLmdbQuerySource.NativeAdjacency knows;
	private NativeLmdbQuerySource.NativeAdjacency interestByObject;
	private long[] knowsSubjects;
	private long[] interestIds;

	@Setup(org.openjdk.jmh.annotations.Level.Trial)
	public void setup() throws Exception {
		FoafCliqueQueryBenchmark.applyEngineMode(engineMode);
		System.setProperty("rdf4j.lmdb.csrCache.minProbes", "1");

		dataDir = Files.createTempDirectory("rdf4j-lmdb-janino-ceiling").toFile();
		repository = FoafCliqueQueryBenchmark.createRepository(dataDir);
		repository.init();
		try (SailRepositoryConnection connection = repository.getConnection()) {
			new FoafCliqueDataGenerator(5000, 30, 3, 8, 15000, 12345).populate(connection);
		}

		LmdbStore store = (LmdbStore) repository.getSail();
		dataset = JaninoCeilingKernels.openDataset(store);
		source = (NativeLmdbQuerySource) dataset;
		probe = source.newProbe();

		long knowsId = source.idOf(vf.createIRI("http://xmlns.com/foaf/0.1/knows"));
		long interestPredId = source.idOf(vf.createIRI("http://xmlns.com/foaf/0.1/interest"));
		interestIds = new long[] {
				source.idOf(vf.createIRI("http://example.org/foaf/meta/interest/rdf")),
				source.idOf(vf.createIRI("http://example.org/foaf/meta/interest/sparql")),
				source.idOf(vf.createIRI("http://example.org/foaf/meta/interest/knowledgeGraphs")) };

		knowsSubjects = JaninoCeilingKernels.distinctSubjects(source, knowsId);
		knows = JaninoCeilingKernels.warmAdjacency(probe, knowsId, true, knowsSubjects);
		interestByObject = JaninoCeilingKernels.warmAdjacency(probe, interestPredId, false, interestIds);
		if (knows == null || interestByObject == null) {
			throw new IllegalStateException("CSR adjacency entries did not build during setup");
		}
	}

	@TearDown(org.openjdk.jmh.annotations.Level.Trial)
	public void tearDown() throws Exception {
		if (probe != null) {
			probe.close();
		}
		if (dataset != null) {
			dataset.close();
		}
		if (repository != null) {
			repository.shutDown();
		}
		if (dataDir != null) {
			FileUtils.deleteDirectory(dataDir);
		}
	}

	@Benchmark
	public long engineCycle3GroupedInterest() {
		return executeCount(FoafCliqueQueryCatalog.QueryScenario.CYCLE3_GROUPED_INTEREST.query());
	}

	@Benchmark
	public long engineCycle4() {
		return executeCount(FoafCliqueQueryCatalog.QueryScenario.CYCLE4.query());
	}

	@Benchmark
	public long fusedCycle3GroupedInterest() {
		long[] counts = JaninoCeilingKernels.cycle3GroupedInterestCounts(knows, interestByObject, interestIds);
		long checksum = 0L;
		for (long count : counts) {
			checksum += count;
		}
		return checksum;
	}

	@Benchmark
	public long fusedCycle4() {
		return JaninoCeilingKernels.cycle4Count(knows, knowsSubjects);
	}

	private long executeCount(String query) {
		try (SailRepositoryConnection connection = repository.getConnection();
				TupleQueryResult result = connection.prepareTupleQuery(QueryLanguage.SPARQL, query).evaluate()) {
			long count = 0L;
			while (result.hasNext()) {
				result.next();
				count++;
			}
			return count;
		}
	}
}
